Deno.serve(async (req) => {
  try {
    const base44 = createClientFromRequest(req);
    const user = await base44.auth.me();

    if (!user) {
      return Response.json({ error: 'Unauthorized' }, { status: 401 });
    }

    const body = await req.json();
    console.log('[LUNA] body keys:', Object.keys(body));
    const { messages, cycleMode, cycleDay, cyclePhase, eddInfo, fertilityMode, menopauseStage, mode = 'quick' } = body;
    const isDeepMode = mode === 'deep';
    const userMessage = messages[messages.length - 1].content;
    console.log('[LUNA] userMessage:', userMessage, 'mode:', mode);

    // ── Initial greeting shortcut ──
    if (messages.length === 1 && userMessage === 'Hello Luna, I just opened the chat.') {
      let greeting = "Hi, I'm Luna 🌙 — your compassionate CycleMind companion.\n\nHow are you feeling today? I'm here to listen and support you through your cycle, pregnancy, or menopausal journey.";
      if (fertilityMode) greeting += " I see you're in fertility mode — I can help track your fertile window and provide conception guidance.";
      else if (menopauseStage) greeting += ` I see you're tracking menopause (${menopauseStage}) — I'm here to support you through this transition.`;
      else if (cyclePhase === 'luteal') greeting += " You're in the luteal phase — be extra gentle with yourself today. Rest when you can, stay hydrated, and know it's okay to do a little less.";
      else if (cyclePhase === 'menstrual') greeting += " You're in your menstrual phase — warmth and rest are your best friends right now. Be kind to your body today.";
      else if (cyclePhase === 'follicular') greeting += " You're in the follicular phase — energy and mood often start to lift here. A good time to do things that feel good for you.";
      else if (cyclePhase === 'ovulatory') greeting += " You're in the ovulatory phase — many women feel their best here. Enjoy the lighter energy if you have it!";

      console.log('[LUNA] route=template');
      return Response.json({
        mainContent: greeting,
        disclaimer: "This is not a substitute for professional medical advice. Please consult your doctor or a mental health professional.",
        source: 'rag',
        suggestedActions: ["Track today's symptoms", "Cycle phase tips", "I need support"],
        flags: { escalate: false, crisis: false },
        timestamp: new Date().toISOString(),
        route: 'template'
      });
    }

    // ── Deep Mode: always Grok, full conversation history, no RAG injection ──
    if (isDeepMode) {
      const contextInfo = [
        `Current context → Cycle mode: ${cycleMode || 'unknown'}`,
        cycleDay ? `Cycle day: ${cycleDay}` : null,
        cyclePhase ? `Cycle phase: ${cyclePhase}` : null,
        eddInfo ? `EDD: ${eddInfo}` : null,
        fertilityMode ? 'FERTILITY MODE ACTIVE' : null,
        menopauseStage ? `MENOPAUSE STAGE: ${menopauseStage}` : null
      ].filter(Boolean).join(' | ');

      const systemContent = LUNA_SYSTEM_PROMPT + '\n\n' + contextInfo +
        '\n\nCURRENT MODE: DEEP — give a richer, more thoughtful reply. Start with "You asked me to think on this with you…"' +
        '\n\nIMPORTANT: Respond ONLY with a valid JSON object with keys: mainContent (string — your response, no disclaimer), suggestedActions (array of strings), flags (object with escalate and crisis booleans).';

      // Pass full conversation history — no RAG injection — so Luna follows the thread
      const conversationMessages = messages.map(m => ({ role: m.role, content: m.content }));

      console.log('[LUNA] route=deep_mode history_length:', messages.length);
      const grokApiKey = Deno.env.get('XAI_API_KEY');
      const grokResponse = await fetch('https://api.x.ai/v1/chat/completions', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json', 'Authorization': `Bearer ${grokApiKey}` },
        body: JSON.stringify({
          model: 'grok-3-mini',
          messages: [{ role: 'system', content: systemContent }, ...conversationMessages],
          response_format: { type: 'json_object' },
          temperature: 0.75,
          max_tokens: 900
        })
      });

      if (!grokResponse.ok) {
        const errBody = await grokResponse.text();
        throw new Error(`Grok deep-mode error: ${grokResponse.status} — ${errBody}`);
      }

      const grokData = await grokResponse.json();
      const rawContent = grokData.choices[0].message.content;
      let deepResult;
      try {
        const parsed = JSON.parse(rawContent);
        const mainContent = (parsed.mainContent || parsed.message || '').replace(/This is not a substitute for professional medical advice\..*$/s, '').trim();
        deepResult = { ...parsed, mainContent, source: 'grok', route: 'deep_grok', modelUsed: 'grok-3-mini' };
      } catch {
        deepResult = { mainContent: rawContent.replace(/This is not a substitute for professional medical advice\..*$/s, '').trim(), suggestedActions: [], flags: { escalate: false, crisis: false }, source: 'grok', route: 'deep_grok', modelUsed: 'grok-3-mini' };
      }
      deepResult.disclaimer = "This is not a substitute for professional medical advice. Please consult your doctor or a mental health professional.";
      return Response.json({ ...deepResult, mode: 'deep', timestamp: new Date().toISOString() });
    }

    // ── Quick Mode: pure RAG, instant response, no Grok call ──
    // Enriched search: combine message + phase + day for best match
    const enrichedQuery = `${userMessage} ${cyclePhase || ''} day ${cycleDay || ''}`.trim();
    const ragResults = ragSearch(enrichedQuery);
    console.log(`[LUNA] rag_search score=${ragResults.score} match_id=${ragResults.bestMatch?.id} category=${ragResults.bestMatch?.category}`);

    if (ragResults.bestMatch && ragResults.score >= 0.15) {
      // Return verbatim RAG entry — no Grok adapt call, sub-second response
      const entry = ragResults.bestMatch;
      const isCrisis = CRISIS_CATEGORIES.has(entry.category);
      console.log(`[LUNA] route=quick_rag_instant category=${entry.category}`);

      // Enforce quick-mode length cap (≤450 chars) to prevent repetitive long openers
      let mainContent = entry.response;
      if (mainContent.length > 450) mainContent = mainContent.substring(0, 420) + '…';

      return Response.json({
        mainContent,
        disclaimer: "This is not a substitute for professional medical advice. Please consult your doctor or a mental health professional.",
        source: 'rag',
        suggestedActions: [],
        flags: { escalate: false, crisis: isCrisis },
        timestamp: new Date().toISOString(),
        route: 'quick_rag_instant',
        modelUsed: 'rag_verbatim'
      });
    }

    // ── Quick Mode Grok fallback (no RAG match) — still enforces short response ──
    const contextInfo = [
      `Current context → Cycle mode: ${cycleMode || 'unknown'}`,
      cycleDay ? `Cycle day: ${cycleDay}` : null,
      cyclePhase ? `Cycle phase: ${cyclePhase}` : null,
      eddInfo ? `EDD: ${eddInfo}` : null,
      fertilityMode ? 'FERTILITY MODE ACTIVE' : null,
      menopauseStage ? `MENOPAUSE STAGE: ${menopauseStage}` : null
    ].filter(Boolean).join(' | ');

    console.log(`[LUNA] route=quick_grok_fallback score=${ragResults.score}`);
    const result = await generateGrokResponse(messages, contextInfo, ragResults, false);
    return Response.json({ ...result, timestamp: new Date().toISOString() });

  } catch (error) {
    console.error('[LUNA] error:', error.message);
    return Response.json({
      mainContent: "I'm having a brief moment connecting, but I'm still here for you. Can you try sending your message again?",
      disclaimer: "This is not a substitute for professional medical advice. Please consult your doctor or a mental health professional.",
      source: 'rag',
      suggestedActions: [],
      flags: { escalate: false, crisis: false },
      timestamp: new Date().toISOString(),
      route: 'fallback'
    }, { status: 200 });
  }
});